INSERT INTO position_questions (categoryId, questionNumber, questionText) VALUES (30, '8', 'Her türlü iletişimde empati kurmaya özen gösterir. Gerektiğinde iletişim tarzını değiştirebilir.');
INSERT INTO position_categories (id, positionId, name) VALUES (31, 3, 'Analitik Düşünme ve Problem Çözme');
INSERT INTO position_questions (categoryId, questionNumber, questionText) VALUES (31, '9', 'Gelişmekte olan problemleri görür, önleyici davranış geliştirir.');
INSERT INTO position_questions (categoryId, questionNumber, questionText) VALUES (31, '10', 'Durum ve problem karşısında alacağı hareketin sonucunu bilir. ');
INSERT INTO position_questions (categoryId, questionNumber, questionText) VALUES (31, '11', 'Mevcut sorunu gidermek için alternatif çözüm yolları geliştirir.');
INSERT INTO position_questions (categoryId, questionNumber, questionText) VALUES (31, '12', 'Benzer sorunlar arasında ilişki kurar; geçmişteki deneyimlerden faydalanır.');
INSERT INTO position_categories (id, positionId, name) VALUES (32, 3, 'Kalite Odaklılık');
INSERT INTO position_questions (categoryId, questionNumber, questionText) VALUES (32, '13', 'Mevcut düzen ve iş yapma yöntemine uygun çalışır. ');
INSERT INTO position_questions (categoryId, questionNumber, questionText) VALUES (32, '14', 'Kaliteyi belirlenen standartlara göre uyarlar.');
INSERT INTO position_questions (categoryId, questionNumber, questionText) VALUES (32, '15', 'İş yapma yöntemini sürekli geliştirmeye, verimlilik ve etkililiği artırmaya odaklı çalışır.');
INSERT INTO position_questions (categoryId, questionNumber, questionText) VALUES (32, '16', 'İş yapma yöntemine ilişkin akış ve prosedürlerdeki yeniliklere adapte olur.');
INSERT INTO position_categories (id, positionId, name) VALUES (33, 3, 'Takım Çalışması ve İşbirliği');
INSERT INTO position_questions (categoryId, questionNumber, questionText) VALUES (33, '17', 'Çalışma ortamında iyi ilişkiler kurar ve korur. ');
INSERT INTO position_questions (categoryId, questionNumber, questionText) VALUES (33, '18', 'Takım arkadaşlarının yardıma ihtiyacı olduğunda gerekli destekte bulunur.');
INSERT INTO position_questions (categoryId, questionNumber, questionText) VALUES (33, '19', 'Takım arkadaşlarını, ortak başarı için heveslendirir, onları motive eder. "Biz" olgusunu yaygınlaştır.');
INSERT INTO position_questions (categoryId, questionNumber, questionText) VALUES (33, '20', 'Takımdaki farklı görüşlere karşı toleranslıdır ve destekleyicidir.');
INSERT INTO position_categories (id, positionId, name) VALUES (34, 3, 'Yönetim Becerileri ');
INSERT INTO position_questions (categoryId, questionNumber, questionText) VALUES (34, '21', 'Doğru insanları belirleyerek ihtiyaçlar doğrultusunda görev dağılımını net bir şekilde yapar. ');
INSERT INTO position_questions (categoryId, questionNumber, questionText) VALUES (34, '22', 'Ekibine mentorluk yapar, yapıcı geri bildirimlerde bulunur ve yönlendirir.');
INSERT INTO position_questions (categoryId, questionNumber, questionText) VALUES (34, '23', 'Ekibini motive eder, olumsuzluk yaratacak durumların önüne geçmek için çaba sarf eder.');
INSERT INTO position_questions (categoryId, questionNumber, questionText) VALUES (34, '24', 'Ekip içindeki anlaşmazlıkları kişiselleştirmeden şirket yararını gözeterek yönetir.');
INSERT INTO position_questions (categoryId, questionNumber, questionText) VALUES (34, '25', 'İnsanların yeteneklerini keşfeder ve doğru şekilde değerlendirir.');
INSERT INTO position_questions (categoryId, questionNumber, questionText) VALUES (34, '26', 'Görevlerin yerine getirilebilmesi için gerekli olan kaynakları belirler ve organize eder.');
INSERT INTO position_questions (categoryId, questionNumber, questionText) VALUES (34, '27', 'Aldığı kararların arkasındadır ve bu kararların sorumluluğunu üstlenir. ');
INSERT INTO position_questions (categoryId, questionNumber, questionText) VALUES (34, '28', 'Zor durumlarda ve baskı altında en etkili kararı verir.');
INSERT INTO position_questions (categoryId, questionNumber, questionText) VALUES (34, '29', 'Çalışanların gelişimi için öğrenme ortamı yaratır. Ekibini ve kendini sürekli geliştirir.');
INSERT INTO position_questions (categoryId, questionNumber, questionText) VALUES (34, '30', 'Davranışları ile ekibe örnek olur. Söyledikleri ile yaptıkları tutarlıdır.');

